commits.content:
.root {
    color: var(--color-white);
}

.moment-home-info__p {
    font-size: 1.125rem;
    font-weight: 300;
    line-height: 1.45;
    padding-right: 9rem;
}

.moment-home-info-wrap {
    color: white;
    background: linear-gradient(210deg, rgba(0, 0, 0, 0) 18.35%, rgba(27, 27, 27, 0.66) 69.12%);
    display: flex;
    align-items: end;
    padding: 4.5rem 5rem 5rem 4.5rem;
    width: 100%;
    height: 100%;
    z-index: 20;
    position: relative;
}
